def diffWaysToCompute(expression: str) -> list[int]:
    memo = {}

    def _compute(s: str) -> list[int]:
        if s in memo:
            return memo[s]

        results = []

        has_operator = False
        for i, char in enumerate(s):
            if char in "+-*":
                has_operator = True
                left_parts = _compute(s[:i])
                right_parts = _compute(s[i+1:])

                for left_val in left_parts:
                    for right_val in right_parts:
                        if char == '+':
                            results.append(left_val + right_val)
                        elif char == '-':
                            results.append(left_val - right_val)
                        elif char == '*':
                            results.append(left_val * right_val)

        if not has_operator:
            results.append(int(s))

        memo[s] = results
        return results

    return _compute(expression)
